import java.util.Scanner;

public class SafeBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Ensure that input length does not exceed buffer size
        int length = Math.min(input.length(), bufferSize);

        // Copy characters from input to buffer with bounds checking
        for (int i = 0; i < length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
